<?php declare(strict_types=1); namespace App\Http\Requests\Payroll; use Illuminate\Foundation\Http\FormRequest; class StorePayrollPeriodRequest extends FormRequest{public function authorize():bool{return $this->user()->can('payroll-periods.manage');} public function rules():array{return ['name'=>'required|string','period_code'=>'required|string','period_start_date'=>'required|date','period_end_date'=>'required|date|after_or_equal:period_start_date','attendance_cutoff_start'=>'required|date','attendance_cutoff_end'=>'required|date|after_or_equal:attendance_cutoff_start','payment_due_date'=>'nullable|date','notes'=>'nullable|string'];}}
